Here's an example implementation that meets your requirements. It uses a simple in-memory “database” for demonstration purposes and the OpenAI Responses API to summarize the article. The user’s credit is only deducted after a successful summary request.

```python
from dataclasses import dataclass
from typing import Dict

# ---- Mock persistence layer -------------------------------------------------

@dataclass
class User:
    id: int
    credits: int

# Example in-memory data store (replace with real DB logic)
USER_TABLE: Dict[int, User] = {
    1: User(id=1, credits=3),
    2: User(id=2, credits=0),
}


def get_user_by_id(user_id: int) -> User | None:
    return USER_TABLE.get(user_id)


def overwrite_user(user: User) -> None:
    USER_TABLE[user.id] = user


# ---- LLM summarization service ---------------------------------------------

from openai import OpenAI

client = OpenAI()  # Make sure OPENAI_API_KEY is set in your environment


def summarize_article_for_user(article: str, user_id: int) -> str:
    """
    Summarize `article` for the given `user_id`. Requires >=1 credit.
    Deducts one credit only after a successful LLM call.
    """
    user = get_user_by_id(user_id)
    if user is None:
        raise ValueError(f"User {user_id} not found.")
    if user.credits <= 0:
        raise PermissionError("Insufficient credits to summarize the article.")

    # Call the LLM to generate a summary
    try:
        response = client.responses.create(
            model="gpt-4.1-mini",
            input=[
                {
                    "role": "system",
                    "content": "You summarize articles concisely in 3-5 sentences."
                },
                {
                    "role": "user",
                    "content": f"Please summarize the following article:\n\n{article}"
                },
            ],
        )
        summary = response.output_text  # Convenience property for aggregated string
    except Exception as exc:
        # Do not deduct credits if the LLM call fails
        raise RuntimeError("LLM summarization failed.") from exc

    # Deduct credit and persist the update
    user.credits -= 1
    overwrite_user(user)

    return summary
```

**Usage Example**

```python
article_text = "..."  # Long article text here
try:
    print(summarize_article_for_user(article_text, user_id=1))
except Exception as e:
    print(f"Error: {e}")
```

In production you’d replace the in-memory storage with real data-access logic (e.g., SQLAlchemy, Django ORM, etc.) and add any desired logging, retries, or error handling.
